.dr-list-panel[data-v-d8d66808],
.dr-detail-panel[data-v-d8d66808] {
    display: flex;
    flex-direction: column;
    background:
        linear-gradient(145deg,
            rgba(var(--bs-primary-rgb), 0.06) 0%,
            rgba(var(--bs-primary-rgb), 0.02) 100%),
        var(--bs-dark);
    border: 1px solid var(--dr-border);
    border-radius: 14px;
    box-shadow:
        0 4px 20px rgba(0, 0, 0, 0.12),
        inset 0 1px 0 rgba(255, 255, 255, 0.04);
    overflow: hidden;
}
.dr-list-panel[data-v-d8d66808] {
    width: 340px;
    flex-shrink: 0;
    max-height: 80vh;
}
.dr-detail-panel[data-v-d8d66808] {
    flex: 1;
    min-width: 0;
    max-height: 80vh;
}
.dr-panel-header[data-v-d8d66808] {
    display: flex;
    align-items: center;
