    font-size: 1rem;
    filter: drop-shadow(0 0 4px rgba(var(--bs-primary-rgb), 0.45));
}
.dr-list-body[data-v-d8d66808] {
    padding: 0.45rem 0.5rem 0.6rem 0.5rem;
    overflow-y: auto;
    flex: 1;
}
.dr-detail-body[data-v-d8d66808] {
    padding: 0;
    overflow-y: auto;
    flex: 1;
}

