.dr-req-item[data-v-d8d66808] {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 0.5rem;
    padding: 0.38rem 0.55rem;
    margin: 0;
    background: transparent;
    border: 0;
    border-bottom: 1px solid rgba(255, 255, 255, 0.05);
    border-radius: 0;
    transition: background 0.15s;
}
.dr-req-item[data-v-d8d66808]:last-child {
    border-bottom: 0;
}
.dr-req-item[data-v-d8d66808]:hover {
    background: rgba(255, 255, 255, 0.03);
}
