    flex: 1;
    min-width: 0;
    color: var(--dr-text);
    font-size: 0.88rem;
    font-weight: 500;
    cursor: help;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

/* ============ List buttons ============ */
.dr-btn[data-v-d8d66808] {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: 0.3rem;
    padding: 0.3rem 0.65rem;
    border-radius: 999px;
    font-size: 0.72rem;
    font-weight: 600;
    letter-spacing: 0.02em;
    cursor: pointer;
    border: 1px solid transparent;
