    flex-shrink: 0;
    min-width: 5.5rem;
}
.dr-btn[data-v-d8d66808]:hover:not(:disabled) {
    filter: brightness(1.15);
    transform: translateY(-1px);
}
.dr-btn[data-v-d8d66808]:disabled {
